import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Login = () => {
  const [formData, setFormData] = useState({
    LoginName: '',
    Password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      console.log('Attempting login with:', formData);
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      console.log('Login response:', response.data);

      if (!response.data) {
        throw new Error('No response data received from server');
      }
      const token = response.data.Token;
      if (!token) {
        throw new Error('No token received from server');
      }
      console.log('Token received:', token);

      let userInfo;
      try {
        const tokenData = JSON.parse(atob(token.split('.')[1]));
        console.log('Decoded token data:', tokenData);
        userInfo = {
          Username: formData.LoginName,
          ClientCode: tokenData.ClientCode
        };
        if (!userInfo.ClientCode) {
          throw new Error('Client code not found in token');
        }
      } catch (tokenError) {
        console.error('Token parsing error:', tokenError);
        throw new Error('Failed to extract client code from token');
      }

      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      // Store login time
      const loginTime = new Date().toLocaleString();
      localStorage.setItem('lastLoginTime', loginTime);
      // Set flag to show welcome toast on dashboard
      localStorage.setItem('showWelcomeToast', 'true');
      console.log('Stored token and userInfo in localStorage');

      toast.success(`Welcome ${userInfo.Username}!`, {
        position: "top-right",
        autoClose: 2000,
        theme: "colored"
      });

      console.log('Navigating to dashboard...');
      navigate('/dashboard');
    } catch (err) {
      console.error('Login error:', err);
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-bg" style={{ minHeight: '90vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <ToastContainer />
      <div className="card-theme fade-in-up" style={{ minWidth: 320, maxWidth: 420, width: '100%', margin: '2rem 0' }}>
        <div className="text-center mb-4">
          <div className="icon-bg-theme" style={{ width: 75, height: 75, margin: '0 auto 1.2rem', fontSize: 36 }}>
            <i className="fas fa-rss"></i>
          </div>
          <h3 className="mb-3 fw-bold text-gradient" style={{ fontSize: '1.8rem', textAlign: 'center', letterSpacing: 0.5 }}>
            <img src="/Logo/Sparkle RFID svg.svg" alt="Sparkle RFID" style={{ height: '40px', marginRight: '8px', verticalAlign: 'middle' }} />
          </h3>
          <h3 className="text-gradient" style={{ fontSize: '2.2rem' }}>RFID Secure API</h3>
          <p style={{ color: '#666', fontSize: '1rem' }}>Login to your account</p>
        </div>
        {error && (
          <div className="alert alert-danger py-2" style={{ fontSize: '0.98rem', borderRadius: '14px', border: 'none', background: 'rgba(220, 53, 69, 0.1)', color: '#dc3545' }}>{error}</div>
        )}
        <form onSubmit={handleSubmit}>
          <div className="form-group mb-3">
            <input type="text" className="input-theme w-100" placeholder="Username" value={formData.LoginName} onChange={handleChange} required />
          </div>
          <div className="form-group mb-3 position-relative">
            <input
              type={showPassword ? 'text' : 'password'}
              className="input-theme w-100"
              placeholder="Password"
              value={formData.Password}
              onChange={handleChange}
              required
            />
            <span
              onClick={() => setShowPassword(s => !s)}
              style={{
                position: 'absolute',
                right: 14,
                top: 'calc(50% - 10px)',
                cursor: 'pointer',
                color: '#0078d4',
                fontSize: '1.1rem',
                zIndex: 10
              }}
              tabIndex={0}
              role="button"
              aria-label="Toggle password visibility"
            >
              <i className={`fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
            </span>
          </div>
          <button type="submit" className="btn-theme w-100" disabled={loading} style={{ marginTop: 8 }}>
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>
        <a href="/register" className="btn-theme btn-theme-red w-100 mt-3" style={{ textAlign: 'center', textDecoration: 'none' }}>Register</a>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Login;
